#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;
const int N=1e5+10;int a[N],t[N],n,w[N];ll m;
ll sm[N<<2],nm[N<<2];int P[N],p;vector<int> T[N];
inline int bnd(int x){int l=1,r=p,m;while(l<=r)P[m=(l+r)>>1]<=x?l=m+1:r=m-1;return l-1;}
inline void add(int qt,int qn,int l=1,int r=p,int x=1)
{
	if(l==r){sm[x]+=1ll*P[l]*qn;nm[x]+=qn;return;} int mid=(l+r)>>1;
	qt<=mid?add(qt,qn,l,mid,x<<1):add(qt,qn,mid+1,r,x<<1|1);
	sm[x]=sm[x<<1]+sm[x<<1|1];nm[x]=nm[x<<1]+nm[x<<1|1];return;
}
inline ll qry(ll qt,int l=1,int r=p,int x=1)
{
	if(l==r)return min(qt/P[l],nm[x]);
	int mid=(l+r)>>1;if(sm[x<<1]>=qt)return qry(qt,l,mid,x<<1);
	return nm[x<<1]+qry(qt-sm[x<<1],mid+1,r,x<<1|1);
}
inline ll dfs(int u,int f,ll qt)
{
	add(t[u],a[u]);ll f1=0,f2=0;
	for(int v:T[u])if(v!=f)
	{
		ll q=dfs(v,u,qt-w[v]);
		if(q>f1)f2=f1,f1=q;else if(q>f2)f2=q;
	}
	ll q=qry(qt);add(t[u],-a[u]);
//	printf("%d :: %lld %lld %lld\n",u,f1,f2,q);
	return max(f2,q);
}
int main()
{
	n=read();scanf("%lld",&m);
	rep(1,n,i)a[i]=read();rep(1,n,i)P[i]=t[i]=read();
	rep(2,n,i)T[read()].push_back(i),w[i]=read()*2;
	sort(P+1,P+n+1);p=unique(P+1,P+n+1)-P-1;rep(1,n,i)t[i]=bnd(t[i]);
	add(t[1],a[1]);ll mx=qry(m);for(int v:T[1])mx=max(mx,dfs(v,1,m-w[v]));
	printf("%lld\n",mx);return 0;
}
